class Solution {
public:
    vector<int> validSequence(string word1, string word2) {
        int n = word1.size(), m = word2.size();
        vector<int> suf(m + 1, n);
        for (int i = m - 1; i >= 0; --i) {
            int pos = (i == m - 1) ? n - 1 : suf[i + 1] - 1;
            while (pos >= 0 && word1[pos] != word2[i]) --pos;
            suf[i] = pos;
        }
        vector<int> res;
        int i = 0, j = 0, diff = 0;
        while (i < n && j < m) {
            if (word1[i] == word2[j] || diff < 1) {
                if (word1[i] != word2[j]) ++diff;
                res.push_back(i);
                if (suf[j + 1] == -1 || suf[j + 1] > i) {
                    ++i; ++j;
                    while (i < n && j < m) {
                        if (word1[i] == word2[j]) {
                            res.push_back(i);
                            ++j;
                        }
                        ++i;
                    }
                    if (j == m) return res;
                    res.pop_back();
                    --j;
                    if (word1[res.back()] != word2[j]) --diff;
                    res.pop_back();
                    ++i;
                    continue;
                }
                ++i; ++j;
            } else {
                ++i;
            }
        }
        if (j == m) return res;
        return {};
    }
};
